css:
* { margin: 0; padding: 0; box-sizing: border-box; }
body { min-height: 100vh; background: linear-gradient(135deg, #052e16, #0a3d20); display: flex; align-items: center; justify-content: center; font-family: -apple-system, BlinkMacSystemFont, sans-serif; }
.page { padding: 20px; }
.card { background: rgba(255,255,255,0.07); border: 1px solid rgba(255,255,255,0.12); border-radius: 28px; padding: 48px 40px; width: 400px; text-align: center; backdrop-filter: blur(20px); color: white; }
.shield-icon { font-size: 56px; margin-bottom: 20px; }
h1 { font-size: 28px; font-weight: 800; margin-bottom: 10px; }
.card p { color: rgba(255,255,255,0.6); font-size: 15px; margin-bottom: 8px; }
.phone-hint { color: #22c55e; font-size: 14px; font-weight: 600; margin-bottom: 32px; }
.code-inputs { display: flex; gap: 10px; justify-content: center; align-items: center; margin-bottom: 8px; }
.code-box { width: 52px; height: 60px; border-radius: 14px; border: 2px solid rgba(255,255,255,0.15); background: rgba(255,255,255,0.08); color: white; font-size: 24px; font-weight: 800; text-align: center; outline: none; transition: all 0.2s; } .code-box:focus { border-color: #22c55e; background: rgba(34,197,94,0.1); }
.code-sep { font-size: 24px; color: rgba(255,255,255,0.3); }
.error-msg { color: #ef4444; font-size: 13px; min-height: 20px; margin-bottom: 8px; }
.verify-btn { width: 100%; height: 52px; border-radius: 16px; border: none; background: linear-gradient(135deg, #22c55e, #16a34a); color: white; font-size: 16px; font-weight: 800; cursor: pointer; margin-bottom: 20px; transition: opacity 0.2s; } .verify-btn:hover { opacity: 0.9; }
.resend-wrap { display: flex; align-items: center; justify-content: center; gap: 8px; font-size: 14px; color: rgba(255,255,255,0.5); margin-bottom: 8px; }
.resend-btn { background: none; border: none; color: #22c55e; font-weight: 700; cursor: pointer; font-size: 14px; } .resend-btn:disabled { color: rgba(255,255,255,0.3); cursor: default; }
.timer { font-size: 12px; color: rgba(255,255,255,0.4); }

js:
const boxes = document.querySelectorAll('.code-box');
let countdown = 30, timerInterval;
function moveNext(el, idx) {
  el.value = el.value.replace(/[^0-9]/g,'');
  if (el.value && idx < 5) boxes[idx+1].focus();
  checkComplete();
}
function checkComplete() {
  const code = [...boxes].map(b => b.value).join('');
  if (code.length === 6) verify();
}
function verify() {
  const code = [...boxes].map(b => b.value).join('');
  const err = document.getElementById('error');
  if (code.length < 6) { err.textContent = '⚠️ Lütfen 6 haneli kodu girin.'; return; }
  if (code === '123456') {
    err.style.color = '#22c55e'; err.textContent = '✓ Doğrulama başarılı! Yönlendiriliyorsunuz...';
    boxes.forEach(b => { b.style.borderColor = '#22c55e'; b.style.background = 'rgba(34,197,94,0.15)'; });
    document.querySelector('.verify-btn').textContent = '✓ Başarılı';
    document.querySelector('.verify-btn').style.background = '#22c55e';
  } else {
    err.style.color = '#ef4444'; err.textContent = '⚠️ Hatalı kod. (İpucu: 123456)';
    boxes.forEach(b => { b.style.borderColor = '#ef4444'; b.value = ''; });
    boxes[0].focus();
    setTimeout(() => { boxes.forEach(b => b.style.borderColor = 'rgba(255,255,255,0.15)'); }, 2000);
  }
}
function resend() {
  const btn = document.getElementById('resend-btn');
  btn.disabled = true; countdown = 30;
  clearInterval(timerInterval);
  timerInterval = setInterval(() => {
    countdown--;
    document.getElementById('timer').textContent = 'Yeni kod için ' + countdown + ' saniye bekle';
    if (countdown <= 0) { clearInterval(timerInterval); btn.disabled = false; document.getElementById('timer').textContent = ''; }
  }, 1000);
  boxes.forEach(b => b.value = '');
  boxes[0].focus();
}
boxes.forEach((box, i) => { box.addEventListener('keydown', e => { if (e.key === 'Backspace' && !box.value && i > 0) boxes[i-1].focus(); }); });
boxes[0].focus();
resend();
